def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    median_capacity = np.median(positive_bins) if positive_bins.size > 0 else 1
    skew_factor = (np.mean((positive_bins - avg_capacity) ** 3) / (variance ** 1.5)) if variance > 0 else 0
    def complex_score(r):
        if r == 1:
            return 0.0
        elif r > 0.9:
            return ((1 - r) ** 7) * 1.5 + 0.3
        elif 0.7 < r <= 0.9:
            return np.log1p((1 - r) * 100) * 0.12
        elif 0.4 < r <= 0.7:
            val = 0.0
            for x in range(1, 12):
                val += ((-1) ** x) * (r ** (x + 2)) / (x ** 1.05)
            return abs(val) + 0.15
        else:
            val = 0.0
            for y in range(1, 15):
                weight = (y ** 0.9) / (y + 1)
                val += ((-1) ** (y + 1)) * (r ** (y + 1)) * weight
            return abs(val) + 0.2
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0 or capacity < item:
            continue
        r = item / capacity
        score = complex_score(r)
        adj_factor = 1.0
        if capacity < median_capacity:
            adj_factor += 0.05 * (median_capacity - capacity) / median_capacity
        else:
            adj_factor -= 0.03 * (capacity - median_capacity) / median_capacity
        score *= adj_factor
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        max_offset = min(10, n)
        for offset in range(1, max_offset + 1):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for nb in neighbors:
                if nb <= 0:
                    continue
                diff = abs(capacity - nb)
                norm_diff = diff / max(capacity, nb)
                weight = 1/(offset ** 1.8)
                influence = norm_diff * weight
                if nb > avg_capacity + variance * 1.5:
                    influence *= 1.15
                elif nb < avg_capacity - variance * 1.5:
                    influence *= 0.85
                neighbors_influence += influence
                neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.6) + (avg_capacity ** 0.4) + (abs(skew_factor) + 1) * 0.5
        penalty = 0.0
        if capacity > 3 * item:
            penalty = 0.07 + 0.01 * np.log(capacity - 3 * item + 1)
        elif capacity < item * 1.2:
            penalty = -0.03 * (capacity / item)
        else:
            penalty = 0.02
        if i % 5 == 0:
            score *= 0.85
            neighbors_influence *= 1.1
            penalty *= 1.05
        elif i % 3 == 0:
            score *= 1.05
            neighbors_influence *= 0.95
        complexity_adjustment = 0.0
        for j in range(n):
            if j == i:
                continue
            diff = abs(bins[j] - capacity)
            complexity_adjustment += np.tanh(diff / (abs(capacity) + 1)) / ((abs(i-j) + 1) ** 2)
        complexity_adjustment /= (n - 1) if n > 1 else 1
        priority = score + (neighbors_influence / cap_factor) + penalty + complexity_adjustment * 0.1
        priorities[i] = max(priority, 0.0)
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 5
    return priorities
